import React, { Component } from 'react';
import nl2br from 'react-newline-to-break'; 

class Cardiology extends React.Component {

    constructor(props) {
        super(props);
        this.state = {  result: {}};
    }

    componentDidMount() {


        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(`http://localhost:9000/cardiology`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {
            //console.log(response);
            this.setState({result: response})
            //console.log(this.state.result)
          })
          .catch(err => {
            console.log(err);
          });

    }


    render() {
        const contents = [];


        var showDiv = <div>Loading ...</div>

        console.log(this.state.result.todayDay)

        if (this.state.result) {
            var showDiv = 
                <div>
                    <div>
                        Good morning,<br></br>
                        Signout will start at <select name="signoutTime" id="signoutTime"><option value="06:00 AM">06:00 AM</option><option value="06:30 AM">06:30 AM</option><option value="07:00 AM">07:00 AM</option><option value="07:30 AM">07:30 AM</option><option value="08:00 AM">08:00 AM</option><option value="08:30 AM" selected>08:30 AM</option></select> today
                    </div>
                </div>
        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px"}}>{showDiv}</div>
        )


    }


}

export default Cardiology;
